Here's a complete data-driven test class for `PriceCalculator` using both `[DataRow]` and `[DynamicData]` with modern MSTest 3.x patterns:

```csharp
using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator = new();

    // ─── CalculateTotal: DataRow for simple inline cases ───

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 5, 0.0, 50.00, DisplayName = "Multiple items, no tax")]
    [DataRow(10.00, 2, 0.10, 22.00, DisplayName = "Two items, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62, DisplayName = "Fractional price, 8% tax")]
    [DataRow(0.00, 10, 0.15, 0.00, DisplayName = "Zero price")]
    [DataRow(99.99, 0, 0.20, 0.00, DisplayName = "Zero quantity")]
    public void CalculateTotal_WithValidInputs_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    [DataRow(-1.00, 1, 0.1, "unitPrice")]
    [DataRow(10.00, -1, 0.1, "quantity")]
    [DataRow(10.00, 1, -0.1, "taxRate")]
    [DataRow(10.00, 1, 1.5, "taxRate")]
    public void CalculateTotal_WithInvalidInputs_ThrowsArgumentOutOfRange(
        double unitPrice, int quantity, double taxRate, string expectedParam)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));

        Assert.AreEqual(expectedParam, ex.ParamName);
    }

    // ─── ApplyDiscount: DynamicData with ValueTuples for type safety ───

    [TestMethod]
    [DynamicData(nameof(DiscountTestData))]
    public void ApplyDiscount_WithValidInputs_ReturnsExpected(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal price, decimal discountPercent, decimal expected)> DiscountTestData =>
    [
        (100m, 0m, 100m),
        (100m, 10m, 90m),
        (100m, 50m, 50m),
        (100m, 100m, 0m),
        (200m, 25m, 150m),
        (59.99m, 15m, 50.9915m),
    ];

    [TestMethod]
    [DataRow(-1.0, DisplayName = "Negative discount")]
    [DataRow(101.0, DisplayName = "Discount over 100%")]
    public void ApplyDiscount_WithInvalidPercent_ThrowsArgumentOutOfRange(double discount)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discount));

        Assert.AreEqual("discountPercent", ex.ParamName);
    }
}
```

**Key patterns used:**

- **`[DataRow]`** — inline primitive values; uses `double` since `decimal` isn't a compile-time constant, cast inside the method
- **`[DynamicData]` with ValueTuples** — preferred for `decimal` data where you need exact types (MSTest 3.7+)
- **`sealed` class**, constructor init, AAA structure
- **`Assert.ThrowsExactly`** instead of `[ExpectedException]`
- **`DisplayName`** for readable test explorer output
- Negative tests verify both the exception type and `ParamName`
